var TOGGLE_FIELDS = ['vehicle_access_height', 'parking_loading_bay', 'lift_restrictions', 'narrow_corridors', 'stairs_involved', 'escort_required', 'site_induction_required', 'manual_handling_required', 'security_procedures'];
var PPE_OPTIONS = ['hi_vis', 'hard_hat', 'safety_boots', 'gloves', 'eye_protection'];
var PPE_LABELS = {
  hi_vis: 'Hi-Vis',
  hard_hat: 'Hard Hat',
  safety_boots: 'Safety Boots',
  gloves: 'Gloves',
  eye_protection: 'Eye Protection'
};
var state = {};
TOGGLE_FIELDS.forEach(function (f) {
  state[f] = false;
});
var selectedPpe = [];
function fmt(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function reviewDue() {
  var d = new Date();
  d.setFullYear(d.getFullYear() + 1);
  return d.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function renderPpeGrid() {
  var grid = document.getElementById('ppe_grid');
  if (!grid) return;
  grid.innerHTML = PPE_OPTIONS.map(function (opt) {
    var isSelected = selectedPpe.indexOf(opt) !== -1;
    return '<div class="ppe-chip' + (isSelected ? ' selected' : '') + '" data-ppe="' + opt + '">' + PPE_LABELS[opt] + '</div>';
  }).join('');
  grid.querySelectorAll('[data-ppe]').forEach(function (chip) {
    chip.addEventListener('click', function () {
      var val = this.dataset.ppe;
      var idx = selectedPpe.indexOf(val);
      if (idx === -1) selectedPpe.push(val);else selectedPpe.splice(idx, 1);
      renderPpeGrid();
    });
  });
}
function setToggleUI(field, value) {
  var btn = document.getElementById('tog_' + field);
  var lbl = document.getElementById('lbl_' + field);
  var con = document.getElementById('con_' + field);
  if (!btn) return;
  btn.className = 'toggle ' + (value ? 'on' : 'off');
  if (lbl) lbl.textContent = value ? 'Yes' : 'No';
  if (con) con.className = 'conditional' + (value ? ' show' : '');
}
function hydrateFromSurvey(survey) {
  if (!survey) {
    TOGGLE_FIELDS.forEach(function (f) {
      state[f] = false;
      setToggleUI(f, false);
    });
    selectedPpe = [];
    renderPpeGrid();
    var blankFields = ['f_vehicle_access_height_notes', 'f_parking_loading_bay_notes', 'f_lift_restrictions_notes', 'f_narrow_corridors_notes', 'f_stairs_involved_notes', 'f_manual_handling_required_notes', 'f_security_procedures_details', 'f_driver_instructions', 'f_site_hazards'];
    blankFields.forEach(function (id) {
      var el = document.getElementById(id);
      if (el) el.value = '';
    });
    return;
  }
  TOGGLE_FIELDS.forEach(function (f) {
    state[f] = !!survey[f];
    setToggleUI(f, state[f]);
  });
  selectedPpe = Array.isArray(survey.ppe_requirements) ? survey.ppe_requirements.slice() : [];
  renderPpeGrid();
  var notesFields = {
    f_vehicle_access_height_notes: survey.vehicle_access_height_notes,
    f_parking_loading_bay_notes: survey.parking_notes,
    f_lift_restrictions_notes: survey.lift_notes,
    f_narrow_corridors_notes: survey.corridor_notes,
    f_stairs_involved_notes: survey.stairs_notes,
    f_manual_handling_required_notes: survey.manual_handling_notes,
    f_security_procedures_details: survey.security_details,
    f_driver_instructions: survey.driver_instructions,
    f_site_hazards: survey.site_hazards
  };
  Object.keys(notesFields).forEach(function (id) {
    var el = document.getElementById(id);
    if (el) el.value = notesFields[id] || '';
  });
}
function render(model) {
  var site = document.getElementById('hdr_site');
  var rdd = document.getElementById('review_due_date');
  var cbn = document.getElementById('completed_by_name');
  if (site) site.textContent = model.site_address || '';
  if (rdd) rdd.textContent = model.existingSurvey ? fmt(model.existingSurvey.last_reviewed_date) : reviewDue();
  if (cbn) cbn.textContent = model.existingSurvey && model.existingSurvey.surveyed_by || model.completed_by || 'Current user';
  hydrateFromSurvey(model.existingSurvey);
}
window.toggle = function (key) {
  state[key] = !state[key];
  setToggleUI(key, state[key]);
};
window.skipSurvey = function () {
  appsmith.triggerEvent('onSkipSurvey');
};
window.saveSurvey = function () {
  appsmith.updateModel({
    ss_vehicle_access_height: state.vehicle_access_height,
    ss_vehicle_access_height_notes: document.getElementById('f_vehicle_access_height_notes').value,
    ss_parking_loading_bay: state.parking_loading_bay,
    ss_parking_loading_bay_notes: document.getElementById('f_parking_loading_bay_notes').value,
    ss_lift_restrictions: state.lift_restrictions,
    ss_lift_restrictions_notes: document.getElementById('f_lift_restrictions_notes').value,
    ss_narrow_corridors: state.narrow_corridors,
    ss_narrow_corridors_notes: document.getElementById('f_narrow_corridors_notes').value,
    ss_stairs_involved: state.stairs_involved,
    ss_stairs_involved_notes: document.getElementById('f_stairs_involved_notes').value,
    ss_escort_required: state.escort_required,
    ss_site_induction_required: state.site_induction_required,
    ss_ppe_requirements: selectedPpe,
    ss_site_hazards: document.getElementById('f_site_hazards').value,
    ss_manual_handling_required: state.manual_handling_required,
    ss_manual_handling_required_notes: document.getElementById('f_manual_handling_required_notes').value,
    ss_security_procedures: state.security_procedures,
    ss_security_procedures_details: document.getElementById('f_security_procedures_details').value,
    ss_driver_instructions: document.getElementById('f_driver_instructions').value
  });
  appsmith.triggerEvent('onSaveSurvey');
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

